import React, { useState, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
    red: '#f87171',
  },
  font: "'JetBrains Mono', monospace",
};

const NUM_EPOCHS = 20;

const round4 = (v) => Math.round(v * 10000) / 10000;

const presets = [
  { label: 'Gentle', gamma: 0.95 },
  { label: 'Standard', gamma: 0.90 },
  { label: 'Fast', gamma: 0.75 },
  { label: 'Aggressive', gamma: 0.50 },
];

export default function App() {
  const [gamma, setGamma] = useState(0.90);
  const [initialLR, setInitialLR] = useState(0.10);
  const [hoveredEpoch, setHoveredEpoch] = useState(null);

  const lrValues = useMemo(() => {
    return Array.from({ length: NUM_EPOCHS + 1 }, (_, e) => ({
      epoch: e,
      lr: round4(initialLR * Math.pow(gamma, e)),
    }));
  }, [gamma, initialLR]);

  const W = 560, H = 240;
  const pad = { t: 24, r: 50, b: 34, l: 56 };
  const plotW = W - pad.l - pad.r;
  const plotH = H - pad.t - pad.b;

  const maxLR = initialLR;

  const toX = (epoch) => pad.l + (epoch / NUM_EPOCHS) * plotW;
  const toY = (lr) => pad.t + plotH - (lr / maxLR) * plotH;

  const linePath = lrValues.map((v, i) => {
    const x = toX(v.epoch);
    const y = toY(Math.min(v.lr, maxLR));
    return (i === 0 ? 'M' : 'L') + ' ' + x.toFixed(1) + ' ' + y.toFixed(1);
  }).join(' ');

  const areaPath = linePath + ' L ' + toX(NUM_EPOCHS).toFixed(1) + ' ' + toY(0).toFixed(1) + ' L ' + toX(0).toFixed(1) + ' ' + toY(0).toFixed(1) + ' Z';

  const hovered = hoveredEpoch !== null ? lrValues[hoveredEpoch] : null;

  const halfLife = gamma < 1 && gamma > 0 ? Math.log(0.5) / Math.log(gamma) : Infinity;

  const getInsight = () => {
    if (gamma >= 0.98) return 'Gamma near 1.0 means almost no decay. The red dashed line (no decay) and blue curve nearly overlap. Without meaningful decay, the model keeps taking large steps and may overshoot the optimum late in training.';
    if (gamma >= 0.93) return 'Gentle decay. The LR halves every ~' + Math.round(halfLife) + ' epochs. Early training uses big steps to explore, then gradually refines. This is why schedulers exist: big steps early for speed, small steps later for precision.';
    if (gamma >= 0.82) return 'Moderate decay: LR halves every ~' + Math.round(halfLife) + ' epochs. Notice the gap between the red line (no decay) and the blue curve growing. That gap is WHY exponential decay helps: it prevents wastefully large updates in later epochs.';
    if (gamma >= 0.65) return 'Fast decay! The LR drops to 10% of its initial value by epoch ' + Math.min(NUM_EPOCHS, Math.round(Math.log(0.1) / Math.log(gamma))) + '. Most learning happens in the first few epochs. Good for fine-tuning a pretrained model where you only need small adjustments.';
    if (gamma >= 0.4) return 'Very aggressive: LR is halved every ' + Math.max(1, Math.round(halfLife)) + ' epoch(s). The curve plunges to near zero almost immediately. Training essentially stops after a few epochs. Usually too aggressive for training from scratch.';
    return 'Extreme decay! The LR essentially vanishes after epoch 1. The model barely learns anything. This shows WHY gamma matters: too low and training stalls, too high and you lose the benefit of decay.';
  };

  const yTicks = [0, 0.25, 0.5, 0.75, 1.0];
  const xTicks = [0, 5, 10, 15, 20];

  return (
    <div style={{ background: theme.colors.background, minHeight: '100vh', padding: '16px', fontFamily: theme.font, color: theme.colors.text }}>
      <div style={{ maxWidth: 600, margin: '0 auto' }}>

        <div style={{ marginBottom: '10px', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div>
            <div style={{ fontSize: '18px', fontWeight: '700' }}>ExponentialLR Scheduler</div>
            <div style={{ fontSize: '11px', color: theme.colors.textSecondary, marginTop: '2px' }}>
              Drag gamma to control decay speed. Hover epochs to trace the math.
            </div>
          </div>
          <button
            onClick={() => { setGamma(0.9); setInitialLR(0.1); setHoveredEpoch(null); }}
            style={{ background: theme.colors.surface, border: '1px solid ' + theme.colors.border, color: theme.colors.textSecondary, padding: '5px 10px', borderRadius: '6px', fontFamily: theme.font, fontSize: '11px', cursor: 'pointer', flexShrink: 0 }}
          >Reset</button>
        </div>

        <div style={{ background: theme.colors.surface, borderRadius: '12px', padding: '14px', border: '1px solid ' + theme.colors.border }}>
          <svg
            width="100%"
            viewBox={'0 0 ' + W + ' ' + H}
            style={{ display: 'block' }}
            onMouseLeave={() => setHoveredEpoch(null)}
          >
            {yTicks.map((frac) => {
              const y = toY(maxLR * frac);
              return (
                <g key={'y' + frac}>
                  <line x1={pad.l} y1={y} x2={W - pad.r} y2={y} stroke={theme.colors.border} strokeWidth={1} />
                  <text x={pad.l - 8} y={y + 4} textAnchor="end" fontSize={9} fill={theme.colors.textSecondary} fontFamily={theme.font}>
                    {(maxLR * frac).toFixed(3)}
                  </text>
                </g>
              );
            })}

            {xTicks.map((e) => (
              <text key={'x' + e} x={toX(e)} y={H - pad.b + 18} textAnchor="middle" fontSize={9} fill={theme.colors.textSecondary} fontFamily={theme.font}>
                {e}
              </text>
            ))}
            <text x={pad.l + plotW / 2} y={H - 2} textAnchor="middle" fontSize={10} fill={theme.colors.textMuted} fontFamily={theme.font}>Epoch</text>
            <text x={14} y={pad.t + plotH / 2} textAnchor="middle" fontSize={10} fill={theme.colors.textMuted} fontFamily={theme.font} transform={'rotate(-90, 14, ' + (pad.t + plotH / 2) + ')'}>
              Learning Rate
            </text>

            <line
              x1={pad.l} y1={toY(initialLR)} x2={W - pad.r} y2={toY(initialLR)}
              stroke={theme.colors.red} strokeWidth={1.5} strokeDasharray="6,4" opacity={0.45}
            />
            <text x={W - pad.r + 4} y={toY(initialLR) + 3} fontSize={8} fill={theme.colors.red} opacity={0.7} fontFamily={theme.font}>
              no decay
            </text>

            <path d={areaPath} fill={theme.colors.blue} opacity={0.07} />
            <path d={linePath} fill="none" stroke={theme.colors.blue} strokeWidth={2.5} strokeLinejoin="round" />

            {lrValues.map((v, i) => {
              const x = toX(v.epoch);
              const y = toY(Math.min(v.lr, maxLR));
              const isH = hoveredEpoch === i;
              return (
                <g key={'d' + i}>
                  <circle
                    cx={x} cy={y} r={14} fill="transparent"
                    onMouseEnter={() => setHoveredEpoch(i)}
                    style={{ cursor: 'pointer' }}
                  />
                  <circle
                    cx={x} cy={y}
                    r={isH ? 5 : 2.5}
                    fill={isH ? theme.colors.yellow : theme.colors.blue}
                    style={{ transition: 'all 0.12s ease' }}
                  />
                </g>
              );
            })}

            {hovered && (() => {
              const x = toX(hovered.epoch);
              const y = toY(Math.min(hovered.lr, maxLR));
              const ttW = 155;
              let ttX = x - ttW / 2;
              ttX = Math.max(pad.l, Math.min(W - pad.r - ttW, ttX));
              const ttY = Math.max(pad.t + 2, y - 50);
              return (
                <g>
                  <line x1={x} y1={y + 6} x2={x} y2={toY(0)} stroke={theme.colors.yellow} strokeWidth={1} strokeDasharray="3,3" opacity={0.4} />
                  <rect x={ttX} y={ttY} width={ttW} height={38} rx={6} fill={theme.colors.surfaceAlt} stroke={theme.colors.yellow} strokeWidth={1} opacity={0.95} />
                  <text x={ttX + 8} y={ttY + 15} fontSize={10} fill={theme.colors.yellow} fontWeight={600} fontFamily={theme.font}>
                    {'Epoch ' + hovered.epoch}
                  </text>
                  <text x={ttX + 8} y={ttY + 30} fontSize={9} fill={theme.colors.textSecondary} fontFamily={theme.font}>
                    {'LR = ' + hovered.lr.toFixed(4)}
                  </text>
                </g>
              );
            })()}
          </svg>

          <div style={{ marginTop: '14px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4px' }}>
              <span style={{ fontSize: '13px', color: theme.colors.blue, fontWeight: 600 }}>gamma</span>
              <div style={{ display: 'flex', gap: '6px', alignItems: 'center' }}>
                {presets.map((p) => (
                  <button
                    key={p.label}
                    onClick={() => setGamma(p.gamma)}
                    style={{
                      padding: '3px 8px',
                      fontSize: '9px',
                      fontFamily: theme.font,
                      border: '1px solid ' + (Math.abs(gamma - p.gamma) < 0.005 ? theme.colors.blue : theme.colors.border),
                      background: Math.abs(gamma - p.gamma) < 0.005 ? theme.colors.blue + '22' : theme.colors.surfaceAlt,
                      color: Math.abs(gamma - p.gamma) < 0.005 ? theme.colors.blue : theme.colors.textSecondary,
                      borderRadius: '4px',
                      cursor: 'pointer',
                    }}
                  >{p.label} ({p.gamma})</button>
                ))}
              </div>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <input
                type="range" min={0.10} max={0.99} step={0.01} value={gamma}
                onChange={(e) => setGamma(parseFloat(e.target.value))}
                style={{ flex: 1, accentColor: theme.colors.blue }}
              />
              <span style={{ fontSize: '18px', fontWeight: 700, color: theme.colors.blue, minWidth: '42px', textAlign: 'right' }}>{gamma.toFixed(2)}</span>
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '9px', color: theme.colors.textMuted, marginTop: '2px' }}>
              <span>0.10 (aggressive decay)</span>
              <span>0.99 (almost no decay)</span>
            </div>
          </div>

          <div style={{ marginTop: '12px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4px' }}>
              <span style={{ fontSize: '11px', color: theme.colors.textSecondary }}>initial_lr</span>
              <span style={{ fontSize: '12px', fontWeight: 600, color: theme.colors.textSecondary }}>{initialLR.toFixed(2)}</span>
            </div>
            <input
              type="range" min={0.01} max={1.0} step={0.01} value={initialLR}
              onChange={(e) => setInitialLR(parseFloat(e.target.value))}
              style={{ width: '100%', accentColor: theme.colors.textMuted }}
            />
          </div>
        </div>

        <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
          <div style={{ flex: 1, background: theme.colors.surface, borderRadius: '8px', padding: '10px', border: '1px solid ' + theme.colors.border }}>
            <div style={{ fontSize: '9px', color: theme.colors.textMuted, marginBottom: '5px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Formula</div>
            <div style={{ fontSize: '13px', color: theme.colors.text }}>
              LR = <span style={{ color: theme.colors.textSecondary }}>{initialLR.toFixed(2)}</span>
              <span style={{ color: theme.colors.textMuted }}> x </span>
              <span style={{ color: theme.colors.blue }}>{gamma.toFixed(2)}</span>
              <span style={{ color: theme.colors.textMuted, verticalAlign: 'super', fontSize: '10px' }}>e</span>
            </div>
            {halfLife !== Infinity && halfLife > 0 && (
              <div style={{ fontSize: '10px', color: theme.colors.textSecondary, marginTop: '5px' }}>
                Half-life: <span style={{ color: theme.colors.yellow, fontWeight: 600 }}>~{halfLife.toFixed(1)} epochs</span>
              </div>
            )}
          </div>

          <div style={{ flex: 1.6, background: theme.colors.surface, borderRadius: '8px', padding: '10px', border: '1px solid ' + theme.colors.border }}>
            <div style={{ fontSize: '9px', color: theme.colors.textMuted, marginBottom: '5px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
              {hovered ? 'Epoch ' + hovered.epoch + ' computation' : 'Hover a dot above'}
            </div>
            {hovered ? (
              <div style={{ fontSize: '12px', lineHeight: 1.6 }}>
                <span style={{ color: theme.colors.textSecondary }}>{initialLR.toFixed(2)}</span>
                <span style={{ color: theme.colors.textMuted }}> x </span>
                <span style={{ color: theme.colors.blue }}>{gamma.toFixed(2)}</span>
                <span style={{ color: theme.colors.textMuted, verticalAlign: 'super', fontSize: '9px' }}>{hovered.epoch}</span>
                <span style={{ color: theme.colors.textMuted }}> = </span>
                <span style={{ color: theme.colors.textSecondary }}>{initialLR.toFixed(2)}</span>
                <span style={{ color: theme.colors.textMuted }}> x </span>
                <span style={{ color: theme.colors.blue }}>{Math.pow(gamma, hovered.epoch).toFixed(4)}</span>
                <span style={{ color: theme.colors.textMuted }}> = </span>
                <span style={{ color: theme.colors.green, fontWeight: 700, fontSize: '14px' }}>{hovered.lr.toFixed(4)}</span>
              </div>
            ) : (
              <div style={{ fontSize: '11px', color: theme.colors.textMuted }}>
                Hover over any dot on the curve to trace the calculation step by step
              </div>
            )}
          </div>
        </div>

        <div style={{
          background: theme.colors.surfaceAlt, borderRadius: '8px', padding: '10px 12px', marginTop: '10px',
          fontSize: '11px', color: theme.colors.textSecondary, borderLeft: '4px solid ' + theme.colors.primary,
          lineHeight: 1.55,
        }}>
          <span style={{ color: theme.colors.primary, fontWeight: 600 }}>Insight: </span>
          {getInsight()}
        </div>
      </div>
    </div>
  );
}

